    "value": {
      "name": "mongod-config",
      "mountPath": "/etc/mongod"
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "mongod-config",
      "configMap": {
        "name": "mongod-config"
      }
    }
  }
]'

for pod in mongodb-replica-0 mongodb-replica-1 mongodb-replica-2; do
  echo "=== $pod ==="
  kubectl exec -n mongodb $pod -- mongosh --quiet "mongodb://admin-user:admin123password@localhost:27017/admin?directConnection=true" --eval "
    var ll = db.adminCommand({getParameter:1, logLevel:1}).logLevel;
    var sm = db.getProfilingStatus().slowms;
    var ss = db.adminCommand({serverStatus:1});
